import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  beforeEach(() => {
    // No external dependencies to mock for this pure function
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path by truncating longer content to maxLength', () => {
    const longText = 'a'.repeat(150);
    const result = truncateContent(longText, 100);
    expect(result.length).toBe(100);
    // ensure the content is the beginning of the original string
    expect(result).toBe(longText.slice(0, 100));
  });

  it('should handle edge case when content length equals maxLength', () => {
    const exactLengthText = 'b'.repeat(80);
    const result = truncateContent(exactLengthText, 80);
    // Should return the original string unchanged
    expect(result).toBe(exactLengthText);
    expect(result.length).toBe(80);
  });

  it('should handle null/empty inputs gracefully', () => {
    // null input
    // @ts-ignore – intentional test of runtime behavior with null
    expect(truncateContent(null, 50)).toBe('');
    // undefined input
    // @ts-ignore – intentional test of runtime behavior with undefined
    expect(truncateContent(undefined, 50)).toBe('');
    // empty string input
    expect(truncateContent('', 50)).toBe('');
    // zero maxLength should result in empty string even with valid content
    expect(truncateContent('some content', 0)).toBe('');
  });
});

